async function handleSystemCommand(payload) {
  const { command, args = [] } = payload;
  console.log('Executing system command:', command, args);
  
  try {
    const result = await execPromise(`${command} ${args.join(' ')}`);
    console.log('Command result:', result.stdout);
  } catch (error) {
    console.error('Command execution failed:', error);
  }
}

